</head>
<body>
  <div class="container">
    <header>
      <h1>Physics Playground</h1>
      <p class="subtitle">Click anywhere inside the box to spawn a ball</p>
    </header>

    <div class="canvas-container">
      <canvas id="sim" width="600" height="600"></canvas>
    </div>

    <div class="controls">
      <button id="drop">Drop Ball</button>
      <button id="play">Pause</button>
      <button id="clear">Clear All</button>
    </div>

    <p class="instructions">Click canvas to add balls • Gravity & edge bounce active</p>
  </div>

  <script>
    (function() {
      const canvas = document.getElementById('sim');
      const ctx = canvas.getContext('2d');

      const CANVAS_WIDTH = 600;
      const CANVAS_HEIGHT = 600;
      canvas.width = CANVAS_WIDTH;
      canvas.height = CANVAS_HEIGHT;

      const dropBtn = document.getElementById('drop');
      const playBtn = document.getElementById('play');
      const clearBtn = document.getElementById('clear');

      let ballsList = [];
      let isRunning = true;

      const GRAVITY = 0.4;
      const RESTITUTION = 0.82;
      const DEFAULT_RADIUS = 18;

      const COLOR_PALETTE = [
        '#ff4757', '#2ed573', '#1e90ff', '#ffa502',
        '#9b59b6', '#ff6b81', '#70a1ff', '#eccc68',
        '#00d2d3', '#ff9ff3', '#54a0ff', '#5f27cd'
      ];

      function getRandomColor() {
        return COLOR_PALETTE[Math.floor(Math.random() * COLOR_PALETTE.length)];
      }

      function addBallImpl(x, y, vx = 0, vy = 0, r) {
        const radius = (r !== undefined && r !== null) ? Number(r) : DEFAULT_RADIUS;
        let cx = Number(x);
        let cy = Number(y);

        // Ensure initially spawned inside boundaries
        cx = Math.max(radius, Math.min(CANVAS_WIDTH - radius, cx));
        cy = Math.max(radius, Math.min(CANVAS_HEIGHT - radius, cy));

        const ball = {
          x: cx,
          y: cy,
          vx: Number(vx),
          vy: Number(vy),
          r: radius,
          color: getRandomColor()
        };

        ballsList.push(ball);
        draw();
        return ball;
      }

      function clearImpl() {
        ballsList = [];
        draw();
      }

      function ballsImpl() {
        return ballsList.map(b => ({
          x: b.x,
          y: b.y,
          vx: b.vx,
          vy: b.vy,
          r: b.r
        }));
      }

      function stepPhysics(dt) {
        dt = Number(dt);
        if (isNaN(dt) || dt <= 0) dt = 1;

        // Substepping logic for high velocities or large dt to eliminate tunneling
        const steps = Math.max(1, Math.ceil(dt));
        const subDt = dt / steps;

        for (let s = 0; s < steps; s++) {
          // 1. Move and check canvas boundaries
          for (let i = 0; i < ballsList.length; i++) {
            const b = ballsList[i];

            // Acceleration due to gravity
            b.vy += GRAVITY * subDt;

            // Integration
            b.x += b.vx * subDt;
            b.y += b.vy * subDt;

            // Boundary collision handling & clamping
            // Left
            if (b.x - b.r < 0) {
              b.x = b.r;
              if (b.vx < 0) b.vx = -b.vx * RESTITUTION;
            }
            // Right
            if (b.x + b.r > CANVAS_WIDTH) {
              b.x = CANVAS_WIDTH - b.r;
              if (b.vx > 0) b.vx = -b.vx * RESTITUTION;
            }
            // Top
            if (b.y - b.r < 0) {
              b.y = b.r;
              if (b.vy < 0) b.vy = -b.vy * RESTITUTION;
            }
            // Bottom
            if (b.y + b.r > CANVAS_HEIGHT) {
              b.y = CANVAS_HEIGHT - b.r;
              if (b.vy > 0) b.vy = -b.vy * RESTITUTION;
            }
          }

          // 2. Ball-to-ball collisions
          for (let i = 0; i < ballsList.length; i++) {
            for (let j = i + 1; j < ballsList.length; j++) {
              const b1 = ballsList[i];
              const b2 = ballsList[j];
              const dx = b2.x - b1.x;
              const dy = b2.y - b1.y;
              const dist = Math.hypot(dx, dy);
              const minDist = b1.r + b2.r;

              if (dist < minDist && dist > 0) {
                const nx = dx / dist;
                const ny = dy / dist;
                const overlap = minDist - dist;

                // Push overlapping balls apart
                b1.x -= nx * overlap * 0.5;
                b1.y -= ny * overlap * 0.5;
                b2.x += nx * overlap * 0.5;
                b2.y += ny * overlap * 0.5;

                // Re-clamp inside boundaries after separation
                b1.x = Math.max(b1.r, Math.min(CANVAS_WIDTH - b1.r, b1.x));
                b1.y = Math.max(b1.r, Math.min(CANVAS_HEIGHT - b1.r, b1.y));
                b2.x = Math.max(b2.r, Math.min(CANVAS_WIDTH - b2.r, b2.x));
                b2.y = Math.max(b2.r, Math.min(CANVAS_HEIGHT - b2.r, b2.y));

                // Impulse exchange along collision normal
                const rvx = b1.vx - b2.vx;
                const rvy = b1.vy - b2.vy;
                const velAlongNormal = rvx * nx + rvy * ny;

                if (velAlongNormal > 0) {
                  const impulse = velAlongNormal * RESTITUTION;
                  b1.vx -= impulse * nx;
                  b1.vy -= impulse * ny;
                  b2.vx += impulse * nx;
                  b2.vy += impulse * ny;
                }
              }
            }
          }
        }
      }

      function stepImpl(dt = 1) {
        stepPhysics(dt);
        draw();
      }

      function draw() {
        ctx.clearRect(0, 0, CANVAS_WIDTH, CANVAS_HEIGHT);

        // Background grid pattern
        ctx.strokeStyle = 'rgba(255, 255, 255, 0.03)';
        ctx.lineWidth = 1;
        const gridGap = 40;
        for (let x = 0; x < CANVAS_WIDTH; x += gridGap) {
          ctx.beginPath();
          ctx.moveTo(x, 0);
          ctx.lineTo(x, CANVAS_HEIGHT);
          ctx.stroke();
        }
        for (let y = 0; y < CANVAS_HEIGHT; y += gridGap) {
          ctx.beginPath();
          ctx.moveTo(0, y);
          ctx.lineTo(CANVAS_WIDTH, y);
          ctx.stroke();
        }

        // Draw balls
        for (let i = 0; i < ballsList.length; i++) {
          const b = ballsList[i];
          ctx.save();

          // Outer shadow/glow
          ctx.shadowColor = b.color;
          ctx.shadowBlur = 10;

          // Main body
          ctx.beginPath();
          ctx.arc(b.x, b.y, b.r, 0, Math.PI * 2);
          ctx.fillStyle = b.color;
          ctx.fill();

          // 3D gloss highlight
          const grad = ctx.createRadialGradient(
            b.x - b.r * 0.3, b.y - b.r * 0.3, b.r * 0.05,
            b.x, b.y, b.r
          );
          grad.addColorStop(0, 'rgba(255, 255, 255, 0.5)');
          grad.addColorStop(0.7, 'rgba(255, 255, 255, 0)');
          ctx.fillStyle = grad;
          ctx.fill();

          // Outline
          ctx.shadowBlur = 0;
          ctx.strokeStyle = 'rgba(255, 255, 255, 0.3)';
          ctx.lineWidth = 1.5;
          ctx.stroke();

          ctx.restore();
        }
      }

      // Main Loop
      function loop() {
        if (isRunning) {
          stepImpl(1);
        }
        requestAnimationFrame(loop);
      }

      // Event Listeners
      canvas.addEventListener('click', (e) => {
        const rect = canvas.getBoundingClientRect();
        const scaleX = canvas.width / rect.width;
        const scaleY = canvas.height / rect.height;
        const x = (e.clientX - rect.left) * scaleX;
        const y = (e.clientY - rect.top) * scaleY;
        const vx = (Math.random() - 0.5) * 8;
        const vy = (Math.random() - 0.5) * 4;
        addBallImpl(x, y, vx, vy);
      });

      dropBtn.addEventListener('click', () => {
        const x = CANVAS_WIDTH / 2 + (Math.random() - 0.5) * 40;
        const y = 40;
        const vx = (Math.random() - 0.5) * 6;
        const vy = Math.random() * 2;
        addBallImpl(x, y, vx, vy);
      });

      playBtn.addEventListener('click', () => {
        isRunning = !isRunning;
        if (isRunning) {
          playBtn.textContent = 'Pause';
          playBtn.classList.remove('paused');
        } else {
          playBtn.textContent = 'Play';
          playBtn.classList.add('paused');
        }
      });

      clearBtn.addEventListener('click', () => {
        clearImpl();
      });

      // Public API contract
      window.sim = {
        w: CANVAS_WIDTH,
        h: CANVAS_HEIGHT,
        balls: ballsImpl,
        addBall: addBallImpl,
        clear: clearImpl,
        step: stepImpl
      };

      // Seed initial balls for immediate visual appeal
      addBallImpl(200, 150, 3, 0, 20);
      addBallImpl(400, 100, -2, 1, 24);
      addBallImpl(300, 80, 1.5, -2, 16);

      // Start loop
      requestAnimationFrame(loop);
    })();
  </script>
</body>
</html>
